```typescript
export type GalleryShowState =
  | { status: "none" }
  | { status: "planned"; id: string; title: string; rooms: number }
  | { status: "open"; id: string; title: string; rooms: number; visitors: number }
  | { status: "closed"; id: string; title: string; totalVisitors: number };

export type GalleryShowCommand =
  | { type: "plan"; id: string; title: string; rooms: number }
  | { type: "open" }
  | { type: "admitVisitor" }
  | { type: "close" };

export type GalleryShowEvent =
  | { type: "GalleryShowPlanned"; id: string; title: string; rooms: number }
  | { type: "GalleryShowOpened" }
  | { type: "GalleryShowVisitorAdmitted" }
  | { type: "GalleryShowClosed"; totalVisitors: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const galleryShowDecider: Decider<GalleryShowCommand, GalleryShowEvent, GalleryShowState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.rooms <= 0) throw new DomainError("INVALID_ROOMS");
        return [{ type: "GalleryShowPlanned", id: command.id, title: command.title, rooms: command.rooms }];
      case "open":
        if (state.status !== "planned") throw new DomainError("NOT_PLANNED");
        return [{ type: "GalleryShowOpened" }];
      case "admitVisitor":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "GalleryShowVisitorAdmitted" }];
      case "close":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "GalleryShowClosed", totalVisitors: state.visitors }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "GalleryShowPlanned":
        return { status: "planned", id: event.id, title: event.title, rooms: event.rooms };
      case "GalleryShowOpened":
        if (state.status !== "planned") return state;
        return { status: "open", id: state.id, title: state.title, rooms: state.rooms, visitors: 0 };
      case "GalleryShowVisitorAdmitted":
        if (state.status !== "open") return state;
        return { ...state, visitors: state.visitors + 1 };
      case "GalleryShowClosed":
        if (state.status !== "open") return state;
        return { status: "closed", id: state.id, title: state.title, totalVisitors: event.totalVisitors };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
