export type PaintingState =
  | { status: "none" }
  | { status: "catalogued"; id: string; artist: string }
  | { status: "authenticated"; id: string; artist: string; cert: string }
  | { status: "rejected"; id: string; reason: string };

export type PaintingCommand =
  | { type: "catalogue"; id: string; artist: string }
  | { type: "authenticate"; cert: string }
  | { type: "reject"; reason: string };

export type PaintingEvent =
  | { type: "PaintingCatalogued"; id: string; artist: string }
  | { type: "PaintingAuthenticated"; cert: string }
  | { type: "PaintingRejected"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const paintingDecider: Decider<PaintingCommand, PaintingEvent, PaintingState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "catalogue":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "PaintingCatalogued", id: command.id, artist: command.artist }];
      case "authenticate":
        if (state.status === "rejected") throw new DomainError("ALREADY_REJECTED");
        if (state.status !== "catalogued") throw new DomainError("NOT_CATALOGUED");
        return [{ type: "PaintingAuthenticated", cert: command.cert }];
      case "reject":
        if (state.status !== "catalogued") throw new DomainError("NOT_CATALOGUED");
        return [{ type: "PaintingRejected", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PaintingCatalogued":
        return { status: "catalogued", id: event.id, artist: event.artist };
      case "PaintingAuthenticated":
        if (state.status !== "catalogued") return state;
        return { status: "authenticated", id: state.id, artist: state.artist, cert: event.cert };
      case "PaintingRejected":
        if (state.status !== "catalogued") return state;
        return { status: "rejected", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
