A Curation aggregate needs three states (none, proposed, approved), a `decide` that refuses double proposals or retracting an approved curation, and an exhaustive `evolve`. Below is a minimal example that keeps the shape consistent with other Deciders in the system.

```typescript
export type CurationState =
  | { status: "none" }
  | { status: "proposed"; id: string; curator: string }
  | { status: "approved"; id: string; curator: string; by: string };

export type CurationCommand =
  | { type: "propose"; id: string; curator: string }
  | { type: "approve"; by: string }
  | { type: "retract"; reason: string };

export type CurationEvent =
  | { type: "CurationProposed"; id: string; curator: string }
  | { type: "CurationApproved"; by: string }
  | { type: "CurationRetracted"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const curationDecider: Decider<CurationCommand, CurationEvent, CurationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "propose":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "CurationProposed", id: command.id, curator: command.curator }];
      case "approve":
        if (state.status !== "proposed") throw new DomainError("NOT_PROPOSED");
        return [{ type: "CurationApproved", by: command.by }];
      case "retract":
        if (state.status !== "proposed") throw new DomainError("CANNOT_RETRACT");
        return [{ type: "CurationRetracted", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CurationProposed":
        return { status: "proposed", id: event.id, curator: event.curator };
      case "CurationApproved":
        if (state.status !== "proposed") return state;
        return { status: "approved", id: state.id, curator: state.curator, by: event.by };
      case "CurationRetracted":
        if (state.status !== "proposed") return state;
        return { status: "none" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
