export type LoanAgreementState =
  | { status: "none" }
  | { status: "drafted"; id: string; borrower: string; pieceId: string }
  | { status: "signed"; id: string; borrower: string; pieceId: string; until: string }
  | { status: "returned"; id: string; returnedAt: string };

export type LoanAgreementCommand =
  | { type: "draft"; id: string; borrower: string; pieceId: string }
  | { type: "sign"; until: string }
  | { type: "return"; returnedAt: string };

export type LoanAgreementEvent =
  | { type: "LoanAgreementDrafted"; id: string; borrower: string; pieceId: string }
  | { type: "LoanAgreementSigned"; until: string }
  | { type: "LoanAgreementReturned"; returnedAt: string };

const initial: LoanAgreementState = { status: "none" };

function evolve(state: LoanAgreementState, event: LoanAgreementEvent): LoanAgreementState {
  switch (event.type) {
    case "LoanAgreementDrafted":
      return { status: "drafted", id: event.id, borrower: event.borrower, pieceId: event.pieceId };
    case "LoanAgreementSigned":
      if (state.status !== "drafted") return state;
      return { status: "signed", id: state.id, borrower: state.borrower, pieceId: state.pieceId, until: event.until };
    case "LoanAgreementReturned":
      if (state.status !== "signed") return state;
      return { status: "returned", id: state.id, returnedAt: event.returnedAt };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: LoanAgreementCommand, state: LoanAgreementState): LoanAgreementEvent[] {
  switch (command.type) {
    case "draft":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "LoanAgreementDrafted", id: command.id, borrower: command.borrower, pieceId: command.pieceId }];
    case "sign":
      if (state.status !== "drafted") throw new Error("NOT_DRAFTED");
      return [{ type: "LoanAgreementSigned", until: command.until }];
    case "return":
      if (state.status !== "signed") throw new Error("NOT_SIGNED");
      return [{ type: "LoanAgreementReturned", returnedAt: command.returnedAt }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handleLoanAgreement(
  command: LoanAgreementCommand,
  ctx: { streamName: string; eventStore: EventStore<LoanAgreementEvent> }
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const out = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, out, { expectedRevision: revision });
}
