```typescript
import { Effect } from "effect";

export type InstallationState =
  | { status: "none" }
  | { status: "planned"; id: string; gallery: string }
  | { status: "built"; id: string; gallery: string; at: string }
  | { status: "dismantled"; id: string; at: string };

export type InstallationCommand =
  | { type: "plan"; id: string; gallery: string }
  | { type: "build"; at: string }
  | { type: "dismantle"; at: string };

export type InstallationEvent =
  | { type: "InstallationPlanned"; id: string; gallery: string }
  | { type: "InstallationBuilt"; at: string }
  | { type: "InstallationDismantled"; at: string };

const initial: InstallationState = { status: "none" };

function evolve(state: InstallationState, event: InstallationEvent): InstallationState {
  switch (event.type) {
    case "InstallationPlanned":
      return { status: "planned", id: event.id, gallery: event.gallery };
    case "InstallationBuilt":
      if (state.status !== "planned") return state;
      return { status: "built", id: state.id, gallery: state.gallery, at: event.at };
    case "InstallationDismantled":
      if (state.status !== "built") return state;
      return { status: "dismantled", id: state.id, at: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: InstallationCommand, state: InstallationState): InstallationEvent[] {
  switch (command.type) {
    case "plan":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "InstallationPlanned", id: command.id, gallery: command.gallery }];
    case "build":
      if (state.status !== "planned") throw new Error("NOT_PLANNED");
      return [{ type: "InstallationBuilt", at: command.at }];
    case "dismantle":
      if (state.status !== "built") throw new Error("NOT_BUILT");
      return [{ type: "InstallationDismantled", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export const handle = (
  command: InstallationCommand,
  ctx: { streamName: string; eventStore: EventStore<InstallationEvent> }
) =>
  Effect.gen(function* () {
    const read = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = read.events.reduce(evolve, initial);
    const produced = decide(command, state);
    yield* Effect.promise(() => ctx.eventStore.appendToStream(ctx.streamName, produced, { expectedRevision: read.revision }));
