```typescript
export type ArtifactState =
  | { status: "none" }
  | { status: "accessioned"; id: string; provenance: string }
  | { status: "loaned"; id: string; borrower: string }
  | { status: "returned"; id: string };

export type ArtifactCommand =
  | { type: "accession"; id: string; provenance: string }
  | { type: "loanOut"; borrower: string }
  | { type: "returnIt" };

export type ArtifactEvent =
  | { type: "ArtifactAccessioned"; id: string; provenance: string }
  | { type: "ArtifactLoanedOut"; borrower: string }
  | { type: "ArtifactReturned" };

const initial: ArtifactState = { status: "none" };

function evolve(state: ArtifactState, event: ArtifactEvent): ArtifactState {
  switch (event.type) {
    case "ArtifactAccessioned":
      return { status: "accessioned", id: event.id, provenance: event.provenance };
    case "ArtifactLoanedOut":
      if (state.status !== "accessioned" && state.status !== "returned") return state;
      return { status: "loaned", id: state.id, borrower: event.borrower };
    case "ArtifactReturned":
      if (state.status !== "loaned") return state;
      return { status: "returned", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: ArtifactCommand, state: ArtifactState): ArtifactEvent[] {
  switch (command.type) {
    case "accession":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ArtifactAccessioned", id: command.id, provenance: command.provenance }];
    case "loanOut":
      if (state.status === "loaned" || state.status === "none") throw new Error("NOT_AVAILABLE");
      return [{ type: "ArtifactLoanedOut", borrower: command.borrower }];
    case "returnIt":
      if (state.status !== "loaned") throw new Error("NOT_LOANED");
      return [{ type: "ArtifactReturned" }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handleArtifact(
  command: ArtifactCommand,
  ctx: { streamName: string; eventStore: EventStore<ArtifactEvent>; dryRun?: boolean }
): Promise<ReadonlyArray<ArtifactEvent>> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initial);
  const produced = decide(command, state);
  if (ctx.dryRun !== true) {
    await ctx.eventStore.appendToStream(ctx.streamName, produced, { expectedRevision: revision });
  }
  return produced;
}
```

