  | { type: "CurationProposed"; id: string; curator: string }
  | { type: "CurationApproved"; by: string };

export async function appendCurationEvents(
  store: EventStore<CurationEvent>,
  stream: string,
  events: ReadonlyArray<CurationEvent>
): Promise<AppendResult> {
  const { revision } = await store.readStream(stream);
  const result = await store.appendToStream(stream, events, { expectedRevision: revision });
  if (!result.ok) {
    throw new ConcurrencyConflict(stream, revision);
  }
  return { nextExpectedRevision: result.nextExpectedRevision };
}
