    case "SculptureReceived":
      return view;
    case "SculptureDisplayed":
      return { ...view, displayed: view.displayed + 1 };
    case "SculptureDeaccessioned":
      return { ...view, deaccessioned: view.deaccessioned + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
