  name: string,
  cursor: Cursor<SculptureEvent>,
  checkpoints: CheckpointStore,
  save: (v: SculptureView) => Promise<void>,
) =>
  Effect.gen(function* () {
    let view = empty;
    const iter = cursor[Symbol.asyncIterator]();
    while (true) {
      const step = yield* Effect.promise(() => iter.next());
      if (step.done) break;
      const { position, event } = step.value;
      view = project(view, event);
      yield* Effect.promise(() => save(view));
      yield* Effect.promise(() => checkpoints.write(name, position));
