export type ExhibitionEvent =
  | { type: "ExhibitionCurated"; id: string; theme: string; pieces: number }
  | { type: "ExhibitionStarted"; id: string }
  | { type: "ExhibitionEnded"; id: string; endedAt: string };

export interface ExhibitionView {
  readonly running: Readonly<Record<string, { theme: string }>>;
  readonly ended: number;
}

const empty: ExhibitionView = { running: {}, ended: 0 };

export interface Batch<E> {
  readonly events: ReadonlyArray<{ position: bigint; event: E }>;
  readonly nextCursor: bigint | null;
}

export interface EventStoreReader<E> {
  readBatch(from: bigint, batchSize: number): Promise<Batch<E>>;
}

export interface RebuildOptions {
  readonly from: bigint;
  readonly batchSize: number;
  readonly project: (view: ExhibitionView, event: ExhibitionEvent) => ExhibitionView;
  readonly persist: (view: ExhibitionView, position: bigint) => Promise<void>;
  readonly reader: EventStoreReader<ExhibitionEvent>;
}

export async function rebuild(options: RebuildOptions): Promise<void> {
  let cursor: bigint | null = options.from;
  let view: ExhibitionView = empty;
  while (cursor !== null) {
    const batch = await options.reader.readBatch(cursor, options.batchSize);
    let last = cursor;
    for (const entry of batch.events) {
      view = options.project(view, entry.event);
      last = entry.position;
    }
    if (batch.events.length > 0) {
      await options.persist(view, last);
    }
    cursor = batch.nextCursor;
  }
}
