export type DonorEvent =
  | { type: "DonorRegistered"; id: string; name: string }
  | { type: "DonorGiftRecorded"; id: string; amount: number; at: string }
  | { type: "DonorDeactivated"; id: string };

export interface DonorView {
  readonly totalsById: Readonly<Record<string, number>>;
}

const empty: DonorView = { totalsById: {} };

function project(view: DonorView, event: DonorEvent): DonorView {
  switch (event.type) {
    case "DonorRegistered":
      return view;
    case "DonorGiftRecorded": {
      const prev = view.totalsById[event.id] ?? 0;
      return { totalsById: { ...view.totalsById, [event.id]: prev + event.amount } };
    }
    case "DonorDeactivated":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface ReadBatch<E> {
  readonly events: ReadonlyArray<{ position: bigint; event: E }>;
  readonly nextCursor: bigint | null;
}

export interface EventReader<E> {
  readBatch(from: bigint, batchSize: number): Promise<ReadBatch<E>>;
}

export async function rebuildDonorView(
  reader: EventReader<DonorEvent>,
  opts: { from: bigint; batchSize: number; persist: (view: DonorView, position: bigint) => Promise<void>; report?: (progress: { position: bigint; processed: number }) => void }
): Promise<DonorView> {
  let cursor: bigint | null = opts.from;
  let view: DonorView = empty;
  let processed = 0;
  while (cursor !== null) {
    const batch = await reader.readBatch(cursor, opts.batchSize);
    let last = cursor;
    for (const entry of batch.events) {
      view = project(view, entry.event);
      last = entry.position;
      processed += 1;
    }
    if (batch.events.length > 0) {
      await opts.persist(view, last);
      opts.report?.({ position: last, processed });
    }
    cursor = batch.nextCursor;
  }
  return view;
}
