  insertOutbox(row: OutboxRow): Promise<void>;
  appendEvents(
    stream: string,
    events: ReadonlyArray<LoanAgreementEvent>,
    opts: { expectedRevision: bigint | "no_stream" | "any" }
  ): Promise<void>;
}

export interface Connection {
  withTransaction<A>(fn: (tx: Tx) => Promise<A>): Promise<A>;
}

// Publisher worker (separate process) polls for rows where publishedAt IS NULL,
// emits them to the broker, then updates publishedAt. Not implemented here.

export const appendWithOutbox = (
  conn: Connection,
  stream: string,
  events: ReadonlyArray<LoanAgreementEvent>,
  rows: ReadonlyArray<OutboxRow>,
  expected: bigint | "no_stream" | "any"
) =>
  Effect.promise(() =>
    conn.withTransaction(async (tx) => {
      await tx.appendEvents(stream, events, { expectedRevision: expected });
      for (const row of rows) {
        await tx.insertOutbox(row);
      }
    }),
  );
